from typing import Any
import psutil


def register(bus):
    THRESHOLD = 80

    @bus.on("tick")
    def monitor_cpu_usage(data: Any):
        value = psutil.cpu_percent(interval=1)

        if value is None:
            return {"to_llm": False}

        if value >= THRESHOLD:
            payload = (
                "CPU usage has exceeded 80%: {value}%"
                .replace("{value}", str(round(value, 1)))
                .replace("{threshold}", str(THRESHOLD))
            )
            return {
                "to_llm": True,
                "payload": payload,
            }

        return {"to_llm": False}

